+/**
+ * Notification log model for tracking sent notification history.
+ *
+ * Every notification dispatched through NotificationService is recorded
+ * as a NotificationLogEntry for auditing and querying.
+ */
+
+import type { NotificationChannel, NotificationType, NotificationPriority } from './notification.js';
+
+/**
+ * Delivery status of a notification.
+ */
+export type DeliveryStatus = 'delivered' | 'failed' | 'suppressed';
+
+/**
+ * A persisted record of a notification that was dispatched.
+ */
+export interface NotificationLogEntry {
+  id: string;
+  /** The original notification ID from the dispatch */
+  notificationId: string;
+  /** Recipient identifier (email, webhook URL, user ID, etc.) */
+  recipient: string;
+  /** Delivery channel used */
+  channel: NotificationChannel;
+  /** Type of notification */
+  type: NotificationType;
+  /** Priority at time of dispatch */
+  priority: NotificationPriority;
+  /** Whether delivery succeeded, failed, or was suppressed */
+  status: DeliveryStatus;
+  /** Error message if delivery failed or was suppressed */
+  error?: string;
+  /** User ID if associated with a specific user */
+  userId?: string;
+  /** When the notification was sent */
+  sentAt: Date;
+  /** When this log entry was created */
+  createdAt: Date;
+}
+
+/**
+ * Query filters for notification history.
+ */
+export interface NotificationLogQuery {
+  userId?: string;
+  recipient?: string;
+  channel?: NotificationChannel;
+  type?: NotificationType;
+  status?: DeliveryStatus;
+  startDate?: Date;
+  endDate?: Date;
+}

