+/**
+ * Notification history service — logs and queries sent notifications.
+ *
+ * Integrated with NotificationService to automatically log every
+ * dispatched notification (delivered, failed, or suppressed).
+ */
+
+import type { NotificationLogEntry, NotificationLogQuery, DeliveryStatus } from '../models/notification-log.js';
+import type { NotificationLogRepository } from '../repositories/notification-log.repository.js';
+import type {
+  CreateNotificationInput,
+  NotificationResult,
+  NotificationPriority,
+} from '../models/notification.js';
+import { Logger } from '../utils/logger.js';
+
+let nextLogId = 1;
+
+function generateLogId(): string {
+  return `nlog-${String(nextLogId++).padStart(4, '0')}`;
+}
+
+/** Reset ID counter — for testing only. */
+export function resetNotificationLogIdCounter(): void {
+  nextLogId = 1;
+}
+
+export class NotificationHistoryService {
+  private logger = new Logger('NotificationHistoryService');
+
+  constructor(private repository: NotificationLogRepository) {}
+
+  /**
+   * Record a notification dispatch result.
+   */
+  logNotification(
+    input: CreateNotificationInput,
+    result: NotificationResult,
+  ): NotificationLogEntry {
+    let status: DeliveryStatus;
+    if (result.success) {
+      status = 'delivered';
+    } else if (result.error === 'Notification suppressed by user preferences') {
+      status = 'suppressed';
+    } else {
+      status = 'failed';
+    }
+
+    const entry: NotificationLogEntry = {
+      id: generateLogId(),
+      notificationId: result.notificationId,
+      recipient: input.recipient,
+      channel: result.channel,
+      type: input.type,
+      priority: input.priority ?? 'normal' as NotificationPriority,
+      status,
+      error: result.error,
+      userId: input.userId,
+      sentAt: result.deliveredAt,
+      createdAt: new Date(),
+    };
+
+    this.repository.save(entry);
+    this.logger.info(
+      `Logged notification ${entry.notificationId}: ${entry.type} via ${entry.channel} → ${entry.status}`,
+    );
+
+    return entry;
+  }
+
+  /**
+   * Get all log entries for a user.
+   */
+  getByUserId(userId: string): NotificationLogEntry[] {
+    return this.repository.findByUserId(userId);
+  }
+
+  /**
+   * Get all log entries for a notification type.
+   */
+  getByType(type: NotificationLogEntry['type']): NotificationLogEntry[] {
+    return this.repository.findByType(type);
+  }
+
+  /**
+   * Get all log entries for a channel.
+   */
+  getByChannel(channel: NotificationLogEntry['channel']): NotificationLogEntry[] {
+    return this.repository.findByChannel(channel);
+  }
+
+  /**
+   * Query log entries with multiple optional filters.
+   */
+  query(filters: NotificationLogQuery): NotificationLogEntry[] {
+    return this.repository.query(filters);
+  }
+
+  /**
+   * Get a single log entry by ID.
+   */
+  getById(id: string): NotificationLogEntry | undefined {
+    return this.repository.findById(id);
+  }
+
+  /**
+   * Get total count of log entries.
+   */
+  count(): number {
+    return this.repository.count();
+  }
+}

