/**
 * Notification log model for tracking sent notification history.
 *
 * Every notification dispatched through NotificationService is recorded
 * as a NotificationLogEntry for auditing and querying.
 */

import type { NotificationChannel, NotificationType, NotificationPriority } from './notification.js';

/**
 * Delivery status of a notification.
 */
export type DeliveryStatus = 'delivered' | 'failed' | 'suppressed';

/**
 * A persisted record of a notification that was dispatched.
 */
export interface NotificationLogEntry {
  id: string;
  /** The original notification ID from the dispatch */
  notificationId: string;
  /** Recipient identifier (email, webhook URL, user ID, etc.) */
  recipient: string;
  /** Delivery channel used */
  channel: NotificationChannel;
  /** Type of notification */
  type: NotificationType;
  /** Priority at time of dispatch */
  priority: NotificationPriority;
  /** Whether delivery succeeded, failed, or was suppressed */
  status: DeliveryStatus;
  /** Error message if delivery failed or was suppressed */
  error?: string;
  /** User ID if associated with a specific user */
  userId?: string;
  /** When the notification was sent */
  sentAt: Date;
  /** When this log entry was created */
  createdAt: Date;
}

/**
 * Query filters for notification history.
 */
export interface NotificationLogQuery {
  userId?: string;
  recipient?: string;
  channel?: NotificationChannel;
  type?: NotificationType;
  status?: DeliveryStatus;
  startDate?: Date;
  endDate?: Date;
}

/**
 * Repository for NotificationLogEntry data access.
 *
 * Extends BaseRepository with notification-log-specific queries.
 */

import type { DatabaseRecord } from '../utils/database.js';
import type { Database } from '../utils/database.js';
import type { NotificationLogEntry, NotificationLogQuery } from '../models/notification-log.js';
import { BaseRepository } from './base.repository.js';

export class NotificationLogRepository extends BaseRepository<NotificationLogEntry> {
  constructor(db: Database) {
    super(db, 'notification_logs');
  }

  protected toDomain(record: DatabaseRecord): NotificationLogEntry {
    return {
      id: record['id'] as string,
      notificationId: record['notificationId'] as string,
      recipient: record['recipient'] as string,
      channel: record['channel'] as NotificationLogEntry['channel'],
      type: record['type'] as NotificationLogEntry['type'],
      priority: record['priority'] as NotificationLogEntry['priority'],
      status: record['status'] as NotificationLogEntry['status'],
      error: record['error'] as string | undefined,
      userId: record['userId'] as string | undefined,
      sentAt: new Date(record['sentAt'] as string),
      createdAt: new Date(record['createdAt'] as string),
    };
  }

  protected toRecord(entity: NotificationLogEntry): DatabaseRecord {
    const record: DatabaseRecord = {
      id: entity.id,
      notificationId: entity.notificationId,
      recipient: entity.recipient,
      channel: entity.channel,
      type: entity.type,
      priority: entity.priority,
      status: entity.status,
      sentAt: entity.sentAt.toISOString(),
      createdAt: entity.createdAt.toISOString(),
    };
    if (entity.error !== undefined) {
      record['error'] = entity.error;
    }
    if (entity.userId !== undefined) {
      record['userId'] = entity.userId;
    }
    return record;
  }

  /**
   * Find log entries by user ID.
   */
  findByUserId(userId: string): NotificationLogEntry[] {
    return this.findAll((entry) => entry.userId === userId);
  }

  /**
   * Find log entries by notification type.
   */
  findByType(type: NotificationLogEntry['type']): NotificationLogEntry[] {
    return this.findAll((entry) => entry.type === type);
  }

  /**
   * Find log entries by channel.
   */
  findByChannel(channel: NotificationLogEntry['channel']): NotificationLogEntry[] {
    return this.findAll((entry) => entry.channel === channel);
  }

  /**
   * Query log entries with multiple optional filters.
   */
  query(filters: NotificationLogQuery): NotificationLogEntry[] {
    return this.findAll((entry) => {
      if (filters.userId !== undefined && entry.userId !== filters.userId) return false;
      if (filters.recipient !== undefined && entry.recipient !== filters.recipient) return false;
      if (filters.channel !== undefined && entry.channel !== filters.channel) return false;
      if (filters.type !== undefined && entry.type !== filters.type) return false;
      if (filters.status !== undefined && entry.status !== filters.status) return false;
      if (filters.startDate !== undefined && entry.sentAt < filters.startDate) return false;
      if (filters.endDate !== undefined && entry.sentAt > filters.endDate) return false;
      return true;
    });
  }
}

/**
 * Notification history service — logs and queries sent notifications.
 *
 * Integrated with NotificationService to automatically log every
 * dispatched notification (delivered, failed, or suppressed).
 */

import type { NotificationLogEntry, NotificationLogQuery, DeliveryStatus } from '../models/notification-log.js';
import type { NotificationLogRepository } from '../repositories/notification-log.repository.js';
import type {
  CreateNotificationInput,
  NotificationResult,
  NotificationPriority,
} from '../models/notification.js';
import { Logger } from '../utils/logger.js';

let nextLogId = 1;

function generateLogId(): string {
  return `nlog-${String(nextLogId++).padStart(4, '0')}`;
}

/** Reset ID counter — for testing only. */
export function resetNotificationLogIdCounter(): void {
  nextLogId = 1;
}

export class NotificationHistoryService {
  private logger = new Logger('NotificationHistoryService');

  constructor(private repository: NotificationLogRepository) {}

  /**
   * Record a notification dispatch result.
   */
  logNotification(
    input: CreateNotificationInput,
    result: NotificationResult,
  ): NotificationLogEntry {
    let status: DeliveryStatus;
    if (result.success) {
      status = 'delivered';
    } else if (result.error === 'Notification suppressed by user preferences') {
      status = 'suppressed';
    } else {
      status = 'failed';
    }

    const entry: NotificationLogEntry = {
      id: generateLogId(),
      notificationId: result.notificationId,
      recipient: input.recipient,
      channel: result.channel,
      type: input.type,
      priority: input.priority ?? 'normal' as NotificationPriority,
      status,
      error: result.error,
      userId: input.userId,
      sentAt: result.deliveredAt,
      createdAt: new Date(),
    };

    this.repository.save(entry);
    this.logger.info(
      `Logged notification ${entry.notificationId}: ${entry.type} via ${entry.channel} → ${entry.status}`,
    );

    return entry;
  }

  /**
   * Get all log entries for a user.
   */
  getByUserId(userId: string): NotificationLogEntry[] {
    return this.repository.findByUserId(userId);
  }

  /**
   * Get all log entries for a notification type.
   */
  getByType(type: NotificationLogEntry['type']): NotificationLogEntry[] {
    return this.repository.findByType(type);
  }

  /**
   * Get all log entries for a channel.
   */
  getByChannel(channel: NotificationLogEntry['channel']): NotificationLogEntry[] {
    return this.repository.findByChannel(channel);
  }

  /**
   * Query log entries with multiple optional filters.
   */
  query(filters: NotificationLogQuery): NotificationLogEntry[] {
    return this.repository.query(filters);
  }

  /**
   * Get a single log entry by ID.
   */
  getById(id: string): NotificationLogEntry | undefined {
    return this.repository.findById(id);
  }

  /**
   * Get total count of log entries.
   */
  count(): number {
    return this.repository.count();
  }
}

