import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { NotificationLogRepository } from '../../src/repositories/notification-log.repository.js';
import {
  NotificationHistoryService,
  resetNotificationLogIdCounter,
} from '../../src/services/notification-history.service.js';
import { NotificationService, resetNotificationIdCounter } from '../../src/services/notification.service.js';
import { EventBus } from '../../src/events/event-bus.js';
import { EmailAdapter, InMemoryTransport } from '../../src/adapters/email.adapter.js';
import type { CreateNotificationInput, NotificationResult } from '../../src/models/notification.js';

function makeInput(overrides?: Partial<CreateNotificationInput>): CreateNotificationInput {
  return {
    type: 'order-confirmation',
    channel: 'email',
    recipient: 'user@example.com',
    subject: 'Test Subject',
    body: 'Test Body',
    priority: 'normal',
    userId: 'user-1',
    ...overrides,
  };
}

function makeResult(overrides?: Partial<NotificationResult>): NotificationResult {
  return {
    notificationId: 'notif-0001',
    channel: 'email',
    success: true,
    deliveredAt: new Date('2026-01-15T10:00:00Z'),
    ...overrides,
  };
}

describe('NotificationHistoryService', () => {
  let db: Database;
  let repo: NotificationLogRepository;
  let service: NotificationHistoryService;

  beforeEach(() => {
    db = new Database();
    repo = new NotificationLogRepository(db);
    service = new NotificationHistoryService(repo);
    resetNotificationLogIdCounter();
  });

  describe('logNotification', () => {
    it('should log a delivered notification', () => {
      const entry = service.logNotification(makeInput(), makeResult());

      expect(entry.id).toBe('nlog-0001');
      expect(entry.notificationId).toBe('notif-0001');
      expect(entry.recipient).toBe('user@example.com');
      expect(entry.channel).toBe('email');
      expect(entry.type).toBe('order-confirmation');
      expect(entry.priority).toBe('normal');
      expect(entry.status).toBe('delivered');
      expect(entry.error).toBeUndefined();
      expect(entry.userId).toBe('user-1');
    });

    it('should log a failed notification', () => {
      const entry = service.logNotification(
        makeInput(),
        makeResult({ success: false, error: 'Transport error' }),
      );

      expect(entry.status).toBe('failed');
      expect(entry.error).toBe('Transport error');
    });

    it('should log a suppressed notification', () => {
      const entry = service.logNotification(
        makeInput(),
        makeResult({ success: false, error: 'Notification suppressed by user preferences' }),
      );

      expect(entry.status).toBe('suppressed');
      expect(entry.error).toBe('Notification suppressed by user preferences');
    });

    it('should generate sequential IDs', () => {
      const entry1 = service.logNotification(makeInput(), makeResult());
      const entry2 = service.logNotification(makeInput(), makeResult({ notificationId: 'notif-0002' }));

      expect(entry1.id).toBe('nlog-0001');
      expect(entry2.id).toBe('nlog-0002');
    });

    it('should persist entries to the repository', () => {
      service.logNotification(makeInput(), makeResult());

      expect(repo.count()).toBe(1);
      const found = repo.findById('nlog-0001');
      expect(found).toBeDefined();
      expect(found!.notificationId).toBe('notif-0001');
    });

    it('should default priority to normal when not specified', () => {
      const input = makeInput();
      delete (input as Record<string, unknown>)['priority'];
      const entry = service.logNotification(input, makeResult());

      expect(entry.priority).toBe('normal');
    });
  });

  describe('getByUserId', () => {
    it('should return entries for a specific user', () => {
      service.logNotification(makeInput({ userId: 'user-1' }), makeResult());
      service.logNotification(makeInput({ userId: 'user-2' }), makeResult({ notificationId: 'notif-0002' }));
      service.logNotification(makeInput({ userId: 'user-1' }), makeResult({ notificationId: 'notif-0003' }));

      const entries = service.getByUserId('user-1');
      expect(entries).toHaveLength(2);
      expect(entries.every((e) => e.userId === 'user-1')).toBe(true);
    });

    it('should return empty array when no entries for user', () => {
      expect(service.getByUserId('nonexistent')).toHaveLength(0);
    });
  });

  describe('getByType', () => {
    it('should return entries for a specific notification type', () => {
      service.logNotification(makeInput({ type: 'order-confirmation' }), makeResult());
      service.logNotification(makeInput({ type: 'user-welcome' }), makeResult({ notificationId: 'notif-0002' }));
      service.logNotification(makeInput({ type: 'order-confirmation' }), makeResult({ notificationId: 'notif-0003' }));

      const entries = service.getByType('order-confirmation');
      expect(entries).toHaveLength(2);
      expect(entries.every((e) => e.type === 'order-confirmation')).toBe(true);
    });
  });

  describe('getByChannel', () => {
    it('should return entries for a specific channel', () => {
      service.logNotification(makeInput({ channel: 'email' }), makeResult());
      service.logNotification(
        makeInput({ channel: 'webhook' }),
        makeResult({ notificationId: 'notif-0002', channel: 'webhook' }),
      );

      const entries = service.getByChannel('email');
      expect(entries).toHaveLength(1);
      expect(entries[0].channel).toBe('email');
    });
  });

  describe('query', () => {
    beforeEach(() => {
      service.logNotification(
        makeInput({ userId: 'user-1', type: 'order-confirmation', channel: 'email' }),
        makeResult({ deliveredAt: new Date('2026-01-15T10:00:00Z') }),
      );
      service.logNotification(
        makeInput({ userId: 'user-1', type: 'user-welcome', channel: 'email' }),
        makeResult({ notificationId: 'notif-0002', deliveredAt: new Date('2026-01-16T10:00:00Z') }),
      );
      service.logNotification(
        makeInput({ userId: 'user-2', type: 'order-confirmation', channel: 'webhook' }),
        makeResult({ notificationId: 'notif-0003', channel: 'webhook', deliveredAt: new Date('2026-01-17T10:00:00Z') }),
      );
      service.logNotification(
        makeInput({ userId: 'user-1', type: 'system-alert', channel: 'email' }),
        makeResult({ notificationId: 'notif-0004', success: false, error: 'Transport error', deliveredAt: new Date('2026-01-18T10:00:00Z') }),
      );
    });

    it('should filter by userId', () => {
      const entries = service.query({ userId: 'user-1' });
      expect(entries).toHaveLength(3);
    });

    it('should filter by type', () => {
      const entries = service.query({ type: 'order-confirmation' });
      expect(entries).toHaveLength(2);
    });

    it('should filter by channel', () => {
      const entries = service.query({ channel: 'webhook' });
      expect(entries).toHaveLength(1);
      expect(entries[0].userId).toBe('user-2');
    });

    it('should filter by status', () => {
      const entries = service.query({ status: 'failed' });
      expect(entries).toHaveLength(1);
      expect(entries[0].type).toBe('system-alert');
    });

    it('should filter by date range', () => {
      const entries = service.query({
        startDate: new Date('2026-01-16T00:00:00Z'),
        endDate: new Date('2026-01-17T23:59:59Z'),
      });
      expect(entries).toHaveLength(2);
    });

    it('should combine multiple filters', () => {
      const entries = service.query({
        userId: 'user-1',
        type: 'order-confirmation',
      });
      expect(entries).toHaveLength(1);
      expect(entries[0].notificationId).toBe('notif-0001');
    });

    it('should return all entries with empty filters', () => {
      const entries = service.query({});
      expect(entries).toHaveLength(4);
    });
  });

  describe('getById', () => {
    it('should return a log entry by ID', () => {
      service.logNotification(makeInput(), makeResult());

      const entry = service.getById('nlog-0001');
      expect(entry).toBeDefined();
      expect(entry!.notificationId).toBe('notif-0001');
    });

    it('should return undefined for nonexistent ID', () => {
      expect(service.getById('nlog-9999')).toBeUndefined();
    });
  });

  describe('count', () => {
    it('should return total log entry count', () => {
      expect(service.count()).toBe(0);

      service.logNotification(makeInput(), makeResult());
      expect(service.count()).toBe(1);

      service.logNotification(makeInput(), makeResult({ notificationId: 'notif-0002' }));
      expect(service.count()).toBe(2);
    });
  });

  describe('integration with NotificationService', () => {
    let eventBus: EventBus;
    let notificationService: NotificationService;
    let transport: InMemoryTransport;

    beforeEach(() => {
      eventBus = new EventBus();
      notificationService = new NotificationService(eventBus);
      transport = new InMemoryTransport();
      const emailAdapter = new EmailAdapter({ fromAddress: 'noreply@test.com', fromName: 'Test' }, transport);
      notificationService.registerAdapter(emailAdapter);
      notificationService.setHistoryService(service);
      resetNotificationIdCounter();
    });

    it('should log notifications dispatched through NotificationService', async () => {
      await notificationService.dispatchNotification(makeInput());

      expect(service.count()).toBe(1);
      const entries = service.getByUserId('user-1');
      expect(entries).toHaveLength(1);
      expect(entries[0].status).toBe('delivered');
      expect(entries[0].recipient).toBe('user@example.com');
      expect(entries[0].type).toBe('order-confirmation');
      expect(entries[0].channel).toBe('email');
    });

    it('should log failed notifications', async () => {
      await notificationService.dispatchNotification(
        makeInput({ channel: 'webhook' }),
      );

      expect(service.count()).toBe(1);
      const entries = service.query({ status: 'failed' });
      expect(entries).toHaveLength(1);
      expect(entries[0].error).toContain('No adapter registered');
    });

    it('should log notifications triggered by events', async () => {
      await eventBus.emit({
        type: 'user:created',
        user: { id: 'user-5', name: 'Jane', email: 'jane@example.com', role: 'member' as const, createdAt: new Date(), updatedAt: new Date() },
        timestamp: new Date(),
      });

      expect(service.count()).toBe(1);
      const entries = service.getByUserId('user-5');
      expect(entries).toHaveLength(1);
      expect(entries[0].type).toBe('user-welcome');
      expect(entries[0].status).toBe('delivered');
    });
  });
});
